#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e5+5;
int n,ans,maxn=0,minn=inf,a[MAXN];
bool vis[MAXN];
int main(void){
    n=read();
    for(int i=1;i<=n;++i)
    {
        a[i]=read();
        minn=min(minn,a[i]);
        maxn=max(maxn,a[i]);
    }
    if((maxn+1)/2<minn)
    {
        putchar('0');
        exit(false);
    }
    sort(a+1,a+n+1);
    int l=n/2,r=n;
    while(l)
    {
        if(a[l]*2>a[r])
        {
            --l;
        }
        else
        {
            ++ans;
            vis[l]=vis[r]=true;
            --l,--r;
            while(r>0&&vis[r])
            {
                --r;
            }
        }
    }
    write(ans);
    return false;
}
